<script>
/**
 * CORE RENDERING ENGINE
 * A custom 3D projection system for a thick, reeded coin.
 */

const canvas = document.getElementById('coin-hero');
const ctx = canvas.getContext('2d');
let animationId;
let startTime = Date.now();
let isPaused = false;

// Coin properties
const COIN_RADIUS = 300;
const COIN_THICKNESS = 40;
const REED_COUNT = 80; // Number of ridges on the edge

function getRotation(t) {
    // t is [0, 1]
    // Rotate around Y (vertical) and X (horizontal flip)
    return {
        y: t * Math.PI * 2,
        x: t * Math.PI
    };
}

function project(x, y, z, rotX, rotY) {
    // Rotation matrices applied to a point
    // Rotate Y
    let x1 = x * Math.cos(rotY) - z * Math.sin(rotY);
    let z1 = x * Math.sin(rotY) + z * Math.cos(rotY);

    // Rotate X
    let y2 = y * Math.cos(rotX) - z1 * Math.sin(rotX);
    let z2 = y * Math.sin(rotX) + z1 * Math.cos(rotX);

    // Simple perspective projection (orthographic-ish for simplicity, but with scaling)
    const scale = 800 / (800 + z2);
    return {
        x: x1 * scale + 400,
        y: y2 * scale + 400,
        z: z2
    };
}

function drawCoin(t, isHero = true) {
    const { x, y } = getRotation(t);
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Light source vector (moving slightly to create "raking" effect)
    const lightX = Math.cos(x * 0.5 + 0.5);
    const lightY = Math.sin(x * 0.5 + 0.5);
    const lightZ = 1;

    // Draw the edge (reeding)
    for (let i = 0; i < REED_COUNT; i++) {
        const angle = (i / REED_COUNT) * Math.PI * 2;
        const px = Math.cos(angle) * COIN_RADIUS;
        const py = Math.sin(angle) * COIN_RADIUS;

        // The edge is a vertical strip from -thickness/2 to +thickness/2
        const points = [];
        for (let j = -COIN_THICKNESS / 2; j <= COIN_THICKNESS / 2; j += 5) {
            points.push(project(px, py, j, x, y));
        }

        // Sort points by Z to draw back-to-front (Painter's Algorithm)
        points.sort((a, b) => b.z - a.z);

        ctx.beginPath();
        ctx.moveTo(points[0].x, points[0].y);
        for (let p of points) ctx.lineTo(p.x, p.y);
        ctx.closePath();

        // Calculate shading based on normal and light
        const nx = Math.cos(angle);
        const ny = Math.sin(angle);
        const nz = 0; // Edge normal is horizontal
        const dot = (nx * lightX + ny * lightY + nz * lightZ);
        const brightness = Math.max(0.2, dot);

        ctx.fillStyle = `rgba(150, 150, 150, ${brightness})`;
        ctx.fill();
        ctx.strokeStyle = `rgba(255, 255, 255, ${brightness * 0.3})`;
        ctx.stroke();
    }

    // Draw Faces
    const frontFacePoints = [];
    for (let i = 0; i < 64; i++) {
        const a = (i / 64) * Math.PI * 2;
        const p = project(Math.cos(a) * COIN_RADIUS, Math.sin(a) * COIN_RADIUS, -COIN_THICKNESS/2, x, y);
        frontFacePoints.push(p);
    }

    const backFacePoints = [];
    for (let i = 0; i < 64; i++) {
        const a = (i / 64) * Math.PI * 2;
        const p = project(Math.cos(a) * COIN_RADIUS, Math.sin(a) * COIN_RADIUS, COIN_THICKNESS/2, x, y);
        backFacePoints.push(p);
    }

    // Determine visibility based on Z-depth of center point
    const frontCenter = project(0, 0, -COIN_THICKNESS/2, x, y);
    const backCenter = project(0, 0, COIN_THICKNESS/2, x, y);

    // Draw Back Face (if visible)
    if (backCenter.z < frontCenter.z) {
        ctx.beginPath();
        backFacePoints.forEach((p, i) => i === 0 ? ctx.moveTo(p.x, p.y) : ctx.lineTo(p.x, p.y));
        ctx.closePath();

        const grad = ctx.createRadialGradient(backCenter.x, backCenter.y, 0, backCenter.x, backCenter.y, COIN_RADIUS);
        grad.addColorStop(0, '#888');
        grad.addColorStop(1, '#444');
        ctx.fillStyle = grad;
        ctx.fill();

        // Back Text: "10,000 TOKENS"
        ctx.fillStyle = 'rgba(255,255,255,0.8)';
        ctx.font = `bold ${COIN_RADIUS/6}px serif`;
        ctx.textAlign = 'center';
        ctx.fillText("10,000", backCenter.x, backCenter.y - 10);
        ctx.font = `${COIN_RADIUS/12}px sans-serif`;
        ctx.fillText("TOKENS", backCenter.x, backCenter.y + 20);
    }

    // Draw Front Face (if visible)
    if (frontCenter.z < backCenter.z) {
        ctx.beginPath();
        frontFacePoints.forEach((p, i) => i === 0 ? ctx.moveTo(p.x, p.y) : ctx.lineTo(p.x, p.y));
        ctx.closePath();

        const grad = ctx.createRadialGradient(frontCenter.x, frontCenter.y, 0, frontCenter.x, frontCenter.y, COIN_RADIUS);
        grad.addColorStop(0, '#aaa');
        grad.addColorStop(1, '#333');
        ctx.fillStyle = grad;
        ctx.fill();

        // Emblem (Raised Relief)
        ctx.strokeStyle = 'rgba(255,255,255,0.4)';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.arc(frontCenter.x, frontCenter.y, COIN_RADIUS * 0.6, 0, Math.PI * 2);
        ctx.stroke();

        // Stylized "W" Emblem
        ctx.lineWidth = 8;
        ctx.lineCap = 'round';
        ctx.beginPath();
        ctx.moveTo(frontCenter.x - 40, frontCenter.y - 20);
        ctx.lineTo(frontCenter.x - 20, frontCenter.y + 30);
        ctx.lineTo(frontCenter.x, frontCenter.y - 10);
        ctx.lineTo(frontCenter.x + 20, frontCenter.y + 30);
        ctx.lineTo(frontCenter.x + 40, frontCenter.y - 20);
        ctx.stroke();

        // Specular Highlight (Raking Light)
        const highlightX = frontCenter.x + Math.cos(x) * COIN_RADIUS * 0.5;
        const highlightY = frontCenter.y + Math.sin(x) * COIN_RADIUS * 0.5;
        const specGrad = ctx.createRadialGradient(highlightX, highlightY, 0, highlightX, highlightY, COIN_RADIUS * 0.8);
        specGrad.addColorStop(0, 'rgba(255,255,255,0.4)');
        specGrad.addColorStop(1, 'rgba(255,255,255,0)');
        ctx.fillStyle = specGrad;
        ctx.fill();
    }
}

// Animation Loop
function animate() {
    if (isPaused) return;
    const now = Date.now();
    const t = (now - startTime) / 10000; // Slow rotation over 10 seconds
    drawCoin(t % 1);
    animationId = requestAnimationFrame(animate);
}

// Initialize Grid Coins
function initGrid() {
    const editions = document.querySelectorAll('.edition');
    editions.forEach((el, idx) => {
        const canvasEl = el.querySelector('.edition-canvas');
        const c = canvasEl.getContext('2d');
        const type = el.dataset.edition;

        // Static render for grid (Front face only)
        c.fillStyle = '#111';
        c.fillRect(0, 0, 300, 300);

        let color = '#cd7f32'; // Bronze
        if (type === 'silver') color = '#c0c0c0';
        if (type === 'gold') color = '#ffd700';
        if (type === 'black') color = '#1a1a1a';

        const grad = c.createRadialGradient(150, 150, 20, 150, 150, 140);
        grad.addColorStop(0, color);
        grad.addColorStop(1, '#000');
        c.fillStyle = grad;

        c.beginPath();
        c.arc(150, 150, 130, 0, Math.PI * 2);
        c.fill();
        c.strokeStyle = 'rgba(255,255,255,0.2)';
        c.lineWidth = 4;
        c.stroke();

        // Emblem on grid
        c.strokeStyle = 'rgba(255,255,255,0.3)';
        c.lineWidth = 6;
        c.beginPath();
        c.arc(150, 150, 80, 0, Math.PI * 2);
        c.stroke();

        c.beginPath();
        c.moveTo(120, 130);
        c.lineTo(135, 170);
        c.lineTo(150, 140);
        c.lineTo(165, 170);
        c.lineTo(180, 130);
        c.stroke();
    });
}

// API Implementation
window.demo = {
    canvas: canvas,
    setTime(t) {
        // t is [0, 1]
        const { x, y } = getRotation(t);
        drawCoin(t);
    },
    pause() {
        isPaused = true;
        cancelAnimationFrame(animationId);
    }
};

// Start
initGrid();
animate();

</script>
</body>
